#include <stdio.h>
#include <stdlib.h>
int compare(const void *a, const void *b) { return (*(int*)a - *(int*)b); }
int main() {
    int n, d;
    scanf("%d %d", &n, &d);
    int arr[n];
    for (int i = 0; i < n; i++) {
        scanf("%d", &arr[i]);
    }
    qsort(arr, n, sizeof(int), compare);
    int count = 1;
    int last = arr[0];
    for (int i = 1; i < n; i++) {
        if (arr[i] - last >= d) {
            count++;
            last = arr[i];
        }
    }
    printf("%d\n", count);
    return 0;
}

